import{c as t,S as a,j as s,m as i}from"./chunks/framework.DvQr6YbT.js";const m=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Knowlery","text":"把你的 vault 变成一个以 review 为中心的知识空间。","tagline":"Knowlery 为 Claude Code 和 OpenCode 提供一个行动优先的 review surface，并把 setup、diagnostics、rules、skills 维护放在 settings 中。","image":{"src":"/knowlery-pot.svg","alt":"Knowlery Knowledge Pot logo"},"actions":[{"theme":"brand","text":"快速开始","link":"/zh/getting-started/"},{"theme":"alt","text":"理解核心概念","link":"/zh/concepts/"}]},"features":[{"title":"行动优先的 Dashboard","details":"在一个页面里查看 Today's move、Suggested moves、当前笔记、最近活动和 weekly summary。"},{"title":"当前笔记 Review","details":"打开一篇 Markdown 笔记后，准备一个用于连接旧笔记、comparisons 和可复用结构的专注 prompt。"},{"title":"Freshness Review","details":"准备本地 request JSON，导入 agent 写出的结果，并在批准后才应用 scalar freshness metadata。"},{"title":"Weekly Summary","details":"基于最近活动生成本地 HTML 报告，必要时再交给 companion agent 打磨。"},{"title":"Knowledge Bundles","details":"把 review 过的知识作为便携 bundle 分享，把别人的 bundle 安装到 Library/，让 /ask 显式检索它们。"},{"title":"Settings 维护","details":"在 Obsidian settings 中运行诊断、维护 rules/schema、切换平台并管理 Skills library。"}]},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md","lastUpdated":1783065655000}`),l={name:"zh/index.md"};function r(o,e,n,d,c,h){return a(),s("div",null,[...e[0]||(e[0]=[i('<section class="knowlery-panel"><h2 id="knowlery-是什么" tabindex="-1">Knowlery 是什么 <a class="header-anchor" href="#knowlery-是什么" aria-label="Permalink to “Knowlery 是什么”">​</a></h2><p>Knowlery 是一个 Obsidian 插件，适合那些希望在 vault 上叠一层 review 导向工作面的人。</p><p>你的自由笔记仍然属于你。Knowlery 给 agent 一个结构化工作区：<code>entities/</code>、<code>concepts/</code>、<code>comparisons/</code>、<code>queries/</code>、<code>KNOWLEDGE.md</code>、<code>SCHEMA.md</code>、<code>INDEX.base</code>、skills、rules、activity receipts、review requests 和平台配置。</p></section><section class="knowlery-grid"><div class="knowlery-card"><h3>面向 Obsidian 用户</h3><p>初始化 vault，保持结构可见，并通过 dashboard review 笔记、活跃线程、freshness suggestions 和 weekly 输出。</p></div><div class="knowlery-card"><h3>面向 agent 工作流</h3><p>为 Claude Code 或 OpenCode 提供持久说明、activity receipts 和稳定的知识地图，而不是每次会话都重新堆上下文。</p></div></section><h2 id="从哪里开始" tabindex="-1">从哪里开始 <a class="header-anchor" href="#从哪里开始" aria-label="Permalink to “从哪里开始”">​</a></h2><ul><li>第一次使用 Knowlery？从 <a href="/zh/getting-started/">快速开始</a> 开始。</li><li>想先理解模型？阅读 <a href="/zh/concepts/">核心概念</a>。</li><li>遇到问题？打开 <a href="/zh/troubleshooting/">故障排查</a>。</li><li>需要精确文件路径和行为？查看 <a href="/zh/reference/">参考</a>。</li></ul>',4)])])}const u=t(l,[["render",r]]);export{m as __pageData,u as default};
